CREATE TABLE coaching_outputs (
    id TEXT PRIMARY KEY,
    agent_id TEXT NOT NULL,
    phase TEXT NOT NULL,
    focus TEXT NOT NULL,
    top_action TEXT NOT NULL,
    daily_ritual TEXT NOT NULL,
    weekly_target TEXT NOT NULL,
    supporting_actions_json TEXT,
    message TEXT NOT NULL,
    character_type TEXT,
    version TEXT NOT NULL,
    generated_at TEXT NOT NULL
  );
INSERT INTO coaching_outputs VALUES(NULL,'agent_mnw4eem2_ek4c3shx','AUTHORITY','Market Positioning & Conversion Mastery','Write a one-paragraph statement of your specific value — what clients get from working with you that they cannot get from anyone else. Say it out loud until you believe it completely. That certainty is what prospects feel.','Spend 20 minutes every morning on market intelligence. Know your local numbers — active listings, days on market, list-to-sale ratio, absorption rate. Walk into every conversation as the most informed person in the room.','5 meaningful database contacts per day this week — calls, texts, or notes. No exceptions. This is the rhythm that restarts everything.','["Build a pre-appointment credibility packet — your market stats, your proof points, your value proposition — and send it to every prospect before you meet.","Track your consultation-to-signed-agreement ratio monthly. Set a target and work toward it deliberately.","Find one mentor, coach, or top producer in your market whose positioning you admire. Study how they communicate their value. Adapt — do not copy.","After every consultation, write down one thing that landed well and one thing you would change. Over 90 days, this debrief practice will transform your conversion rate."]',replace('THE TRUTH\nGenerating leads consistently takes real discipline, and you are doing that work. The opportunity the System sees is not in your prospecting — it is in what happens after the lead arrives. When a prospect chooses another agent, it is rarely because that agent was more qualified. It is because their positioning was clearer. The gap here is not effort. It is the communication of your value — and that is one of the most learnable skills in this business.\n\n---\n\nTHE STRATEGY\nThe System is going to sharpen your positioning until choosing you feels like the only logical decision. Authority in this market is not built on personality — it is built on demonstrated expertise, consistent presence, and a clear value proposition that prospects feel before they ever meet you in person.\n\n---\n\nTHE TACTICS\n1. Write your personal value proposition this week — one clear paragraph that answers the question every prospect is silently asking: "Why you, specifically, over every other agent in this market?" Not your biography. Your differentiated value. What do your clients get that they cannot get anywhere else?\n\n2. Practice your consultation opening out loud, every day this week. The first 5 minutes of any buyer or listing appointment should establish your authority before you discuss a single property or price. Practice it until it feels like a conversation, not a script.\n\n3. Identify the 3 objections you hear most consistently — "I want to think about it," "I know another agent," "What are your fees?" — and develop a confident, empathetic response to each. Write them down. Role-play them. Own them.\n\n---\n\nYOUR OBJECTIVE THIS WEEK\n5 meaningful database contacts per day this week — calls, texts, or notes. No exceptions. This is the rhythm that restarts everything.\n\n---\n\nYOUR COACHING TRACK\nSphere Saturation — Your warmest pipeline is already in your phone. Activate it before building anything new.','\n',char(10)),'The Authority','v1.1-intermediate','2026-04-15 21:32:23');
INSERT INTO coaching_outputs VALUES(NULL,'agent_mnw4oi77_zuz633h1','PIPELINE','Follow-Up Systems & Pipeline Conversion','Open your pipeline right now and identify the 3 leads you have been meaning to call. Call them today. The discomfort you feel about those calls is the exact cost of not having a system. The System starts today.','Every morning, identify your top 3 follow-up priorities for the day. Complete those 3 contacts before 11am. Everything else — email, admin, social — comes after.','Contact every Hot lead in your pipeline before Friday. Not email — a call. One conversation this week can change your month.','["Script and practice your re-engagement conversation for leads gone cold. Role-play it with a colleague until it feels natural — not rehearsed.","For every showing or consultation that does not convert immediately, set a specific follow-up task before you leave the appointment. Not tomorrow. Before you leave.","Identify your personal follow-up ceiling — the number of active leads you can realistically manage with quality. Do not take on more than you can follow up with properly.","Review your last 10 lost deals. At what point did follow-up stop? That point is where the System will focus."]',replace('THE TRUTH\nManaging a pipeline while trying to prospect, serve clients, and run a business is a real juggling act — and most agents drop the follow-up ball not because they do not care, but because no system exists to catch it. What the data shows is not a motivation gap. It is a rhythm gap. The leads are there. The potential is there. What is missing is a consistent follow-up structure that runs independent of how your week is going. That is exactly what the System builds.\n\n---\n\nTHE STRATEGY\nThe System is going to install a follow-up rhythm that runs whether you feel like it or not. The highest-converting agents are not more motivated than you — they have built infrastructure that makes consistent follow-up the path of least resistance. We are going to build that infrastructure in your business this week.\n\n---\n\nTHE TACTICS\n1. Audit your pipeline today — right now, before anything else. Every lead gets a category: Hot (deciding in 30 days), Warm (60-90 days), Long-term (6+ months). If you cannot categorize a lead, your first step is a call to find out where they stand. You cannot manage what you have not measured.\n\n2. Every Hot lead in your pipeline gets a personal call this week. Not a text. Not an email. A call. Some of those conversations will surprise you. The leads you assumed were cold may simply be waiting to hear from you again.\n\n3. Block 60 minutes tomorrow morning exclusively for follow-up calls. No email. No admin. One hour of focused outreach. Do this three times this week. Notice how your pipeline feels different by Friday.\n\n---\n\nYOUR OBJECTIVE THIS WEEK\nContact every Hot lead in your pipeline before Friday. Not email — a call. One conversation this week can change your month.\n\n---\n\nYOUR COACHING TRACK\nSphere Saturation — Your warmest pipeline is already in your phone. Activate it before building anything new.','\n',char(10)),'The Closer','v1.0-baseline','2026-04-15 21:32:23');
